import (
	context "context"
	fern "github.com/websocket-inferred-auth/fern"
	fernclient "github.com/websocket-inferred-auth/fern/client"
)

client := fernclient.NewClient()
response, err := client.Auth.Gettokenwithclientcredentials(
	context.TODO(),
	&fern.AuthGetTokenWithClientCredentialsRequest{
		ClientID:     "client_id",
		ClientSecret: "client_secret",
		Audience:     fern.AuthGetTokenWithClientCredentialsRequestAudienceHttpsApiExampleCom,
		GrantType:    fern.AuthGetTokenWithClientCredentialsRequestGrantTypeClientCredentials,
	},
)

import (
	context "context"
	fern "github.com/websocket-inferred-auth/fern"
	fernclient "github.com/websocket-inferred-auth/fern/client"
)

client := fernclient.NewClient()
response, err := client.Auth.Refreshtoken(
	context.TODO(),
	&fern.AuthRefreshTokenRequest{
		ClientID:     "client_id",
		ClientSecret: "client_secret",
		RefreshToken: "refresh_token",
		Audience:     fern.AuthRefreshTokenRequestAudienceHttpsApiExampleCom,
		GrantType:    fern.AuthRefreshTokenRequestGrantTypeRefreshToken,
	},
)
